    class EarningsService {
      /**
       * Fetch profile balance from external API via background script
       * (Background script proxies HTTP request to bypass mixed content restrictions)
       */
      static async getProfileBalance(profileId) {
        try {
          const token = localStorage.getItem("token");
          if (token) chrome.storage.local.set({ alpha_token: token });
          if (!token) return null;

          const date = new Date().toISOString().split("T")[0];

          // --- ИСПРАВЛЕНИЕ НАЧАЛО ---
          // Убрали `${token}@` из ссылки и добавили headers
          const response = await fetch(
            `https://alpha.date/api/statistic/profileActionGrouped?date_from=${date}&date_to=${date}`,
            {
              method: "GET",
              headers: {
                Authorization: `Bearer ${token}`, // Передаем токен безопасно
                "Content-Type": "application/json",
              },
            },
          );
          // --- ИСПРАВЛЕНИЕ КОНЕЦ ---

          if (!response.ok) throw new Error("Network response was not ok");

          const data = await response.json();
          // Find the specific profile's stats
          // The API returns an array of stats, we need to find the one matching our profileId
          // Note: API might return string IDs, so we use loose equality
          const profileStats = data.find(
            (stat) => stat.profile_id == profileId,
          );
          if (profileStats) {
            return parseFloat(profileStats.amount).toFixed(2);
          }
          return "0.00";
        } catch (error) {
          console.error("Error fetching balance:", error);
          return null;
        }
      }
    } // ./src/content-script/components/balance/ProfileBalance.tsx

