  // --- ФИНАЛЬНЫЙ МОДУЛЬ БАЛАНСА v5 (Под структуру Grouped) ---



  let balanceCache = { data: null, lastUpdate: 0, ttl: 30000 };

  chrome.runtime.onMessage.addListener((request, sender, sendResponse) => {
    if (request.type === "GET_BALANCE_SAFE") {
      const now = Date.now();

      // 1. КЭШ
      if (
        balanceCache.data &&
        now - balanceCache.lastUpdate < balanceCache.ttl
      ) {

        sendResponse(balanceCache.data);
        return true;
      }

      // 2. ЗАПРОС
      (async () => {
        const token = localStorage.getItem("token");
        if (!token) {
          sendResponse({ error: "Нет токена" });
          return;
        }

        try {
          const today = new Date().toISOString().split("T")[0];

          const response = await fetch(
            `https://alpha.date/api/statistic/profileActionGrouped?date_from=${today}&date_to=${today}`,
            {
              method: "GET",
              headers: {
                Authorization: `Bearer ${token}`,
                Accept: "application/json",
                "X-Requested-With": "XMLHttpRequest",
              },
            },
          );

          if (!response.ok) throw new Error(`Status: ${response.status}`);

          const data = await response.json();


          let total = 0;

          // --- НОВАЯ ЛОГИКА (ПОД ТВОЙ JSON) ---
          if (data && data.status === true && Array.isArray(data.response)) {
            // 1. Ищем строку, где date = "Total" (это сумма за выбранный период)
            const totalRow = data.response.find(
              (item) => item.date === "Total",
            );

            if (totalRow && totalRow.total) {
              total = parseFloat(totalRow.total);
            }
            // 2. Если вдруг строки Total нет (бывает, если только 1 день), берем первую запись
            else if (data.response.length > 0 && data.response[0].total) {
              total = parseFloat(data.response[0].total);
            }
          }



          const result = { total: total, cached: false };
          balanceCache.data = result;
          balanceCache.lastUpdate = Date.now();

          sendResponse(result);
        } catch (err) {
          console.error("[Telescope Error]", err);
          sendResponse({ error: err.message });
        }
      })();
      return true;
    }
  });
